{
  "schema_name": "eywa_node_response",
  "schema_version": "v1",
  "orchestration_decision": "delegate",
  "decision_notes": "The problem requires solving a self-consistent mean-field equation for the occupancy of a lattice gas. I will split this into calculating the energy parameter and then finding the root of the transcendental equation.",
  "helpers": [
    {
      "label": "parameter_calculator",
      "instructions": "Calculate the numerical value of the energy parameter epsilon using the formula e = -(k_B * T) / (2 * pi). Use k_B = 1.380649e-23 J/K and T = 300 K. Note that the result should be expressed in units of k_B * T to simplify the subsequent transcendental equation. Specifically, find the value of epsilon_scaled = e / (k_B * T)."
    },
    {
      "label": "root_finder",
      "instructions": "Solve for the occupancy n in the mean-field equation for a lattice gas. The equation is n = 1 / (exp((epsilon_scaled + z * n) - mu_scaled) + 1), where z is the coordination number. In this specific problem, the coordination number z is the sum of horizontal and vertical neighbors: z = z_h + z_v. Use the following values: z_h = 4, z_v = 8, mu_scaled = 0.1, and the epsilon_scaled value provided by the previous helper. Find the value of n between 0 and 1 that satisfies this equation."
    }
  ],
  "synthesis_brief": "Take the epsilon_scaled value from the parameter_calculator and provide it to the root_finder. The final answer is the value of n returned by the root_finder."
}

